import android.content.SharedPreferences;
import android.os.Bundle;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import java.util.concurrent.Executor;

public class MainActivity extends AppCompatActivity {

    private static final String PREFS_NAME = "biometric_prefs";
    private static final String BIO_AUTH_ENABLED = "bio_auth_enabled";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        if (isBiometricAuthenticationEnabled()) {
            showBiometricPrompt();
        } else {
            setContentView(R.layout.activity_login);
        }
    }

    private boolean isBiometricAuthenticationEnabled() {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
        return prefs.getBoolean(BIO_AUTH_ENABLED, false) && BiometricManager.from(this).canAuthenticate() == BiometricManager.BIOMETRIC_SUCCESS;
    }

    private void showBiometricPrompt() {
        Executor executor = ContextCompat.getMainExecutor(this);
        BiometricPrompt biometricPrompt = new BiometricPrompt(MainActivity.this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                navigateToHome(); // Navigate to the main screen of the app
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                // Handle failed authentication
            }
        });

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("App Authentication")
                .setSubtitle("Use your fingerprint to authenticate")
                .setDeviceCredentialAllowed(false)
                .setNegativeButtonText("Cancel")
                .build();

        biometricPrompt.authenticate(promptInfo);
    }

    private void navigateToHome() {
        // Logic to navigate to the main activity of the app
        setContentView(R.layout.activity_main); // Adjust according to your layout
    }

    private void enableBiometricAuthentication(boolean enable) {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
        SharedPreferences.Editor editor = prefs.edit();
        editor.putBoolean(BIO_AUTH_ENABLED, enable);
        editor.apply();
    }

    // Remember to call enableBiometricAuthentication(true) after user enables biometric login
}